import{_ as r,C as n,o as l,c as s,E as i,w as a,a as o,a0 as d}from"./chunks/framework.CkNTPv-z.js";const v=JSON.parse('{"title":"Moving to Poland","description":"Immigration pathways and relocation guide for Poland","frontmatter":{"layout":"doc","title":"Moving to Poland","description":"Immigration pathways and relocation guide for Poland"},"headers":[],"relativePath":"europe/poland/moving-there.md","filePath":"europe/poland/moving-there.md","lastUpdated":null}'),h={name:"europe/poland/moving-there.md"};function g(u,t,c,m,f,p){const e=n("Badge");return l(),s("div",null,[i(e,{variant:"green"},{default:a(()=>[...t[0]||(t[0]=[o("EU: Free Movement",-1)])]),_:1}),i(e,{variant:"yellow"},{default:a(()=>[...t[1]||(t[1]=[o("Non-EU: Work Visa",-1)])]),_:1}),i(e,{variant:"yellow"},{default:a(()=>[...t[2]||(t[2]=[o("No Specific DN Visa",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="moving-to-poland" tabindex="-1">Moving to Poland <a class="header-anchor" href="#moving-to-poland" aria-label="Permalink to &quot;Moving to Poland&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><ul><li><strong>Free movement rights</strong> — no visa required</li><li><strong>Up to 3 months</strong>: No registration needed</li><li><strong>Over 3 months</strong>: Register with the Voivodeship Office (Urząd Wojewódzki)</li><li><strong>Right to work</strong>: Automatic</li><li><strong>PESEL number</strong>: Required for all services</li></ul><h3 id="uk-citizens-post-brexit" tabindex="-1">UK Citizens (Post-Brexit) <a class="header-anchor" href="#uk-citizens-post-brexit" aria-label="Permalink to &quot;UK Citizens (Post-Brexit)&quot;">​</a></h3><ul><li><strong>Schengen Area</strong>: Visa-free for up to 90 days in any 180-day period</li><li><strong>Long-term residency</strong>: Requires a residence permit: <ul><li>Work permit (job offer from Polish employer)</li><li>Student visa (enrollment at Polish university)</li><li>Family reunification</li><li>Poland Business Harbour (tech sector program)</li></ul></li></ul><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Permit</td><td>Job offer from Polish employer</td><td>Up to 3 years, renewable</td></tr><tr><td>Student Visa</td><td>Enrollment at accredited institution</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family ties to Polish resident</td><td>Tied to sponsor&#39;s status</td></tr><tr><td>EU Blue Card</td><td>Highly skilled (salary ~€30,000+/year)</td><td>Up to 3 years</td></tr><tr><td>Poland Business Harbour</td><td>Tech workers, IT professionals</td><td>Up to 2 years</td></tr></tbody></table><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Poland does <strong>not have a dedicated digital nomad visa</strong>. Options:</p><ul><li><strong>Work visa</strong> if employed by a Polish company</li><li><strong>Tourist visa</strong> for up to 90 days (no work permitted)</li><li><strong>Poland Business Harbour</strong> for tech sector remote workers</li><li>Some remote workers use the <strong>short-term work visa</strong> for specific projects</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for duration of stay</li><li>[ ] <strong>Visa</strong>: Apply 2-3 months in advance (non-EU)</li><li>[ ] <strong>Healthcare</strong>: Private health insurance initially; register with NFZ after residency</li><li>[ ] <strong>HRT</strong>: Get 6-month supply and doctor&#39;s letter (translated to Polish)</li><li>[ ] <strong>Banking</strong>: Consider PKO BP, ING, mBank, or Revolut</li><li>[ ] <strong>Housing</strong>: Research rental market (otodom.pl, olx.pl)</li><li>[ ] <strong>Language</strong>: Polish helpful; English moderate in cities</li><li>[ ] <strong>Document translation</strong>: Official Polish translations needed</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register with Voivodeship Office (non-EU) or municipality (EU)</li><li>[ ] Obtain PESEL number (personal ID) — essential for all services</li><li>[ ] Register with NFZ (National Health Fund)</li><li>[ ] Open local bank account</li><li>[ ] Get local SIM card (Orange, Play, T-Mobile, Plus)</li><li>[ ] Connect with LGBTQ+ community (KPH, Trans-Fuzja)</li><li>[ ] Register with sexuology clinic for trans healthcare</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li><strong>Low to moderate</strong> — varies by city</li><li>Monthly rent (1-bed): €400-900 (Warsaw), €350-700 (Kraków), €300-550 (Wrocław), €250-450 (Łódź)</li><li>Monthly groceries: €200-350</li><li>Public transport: €25-35/month (major cities)</li><li>Dining out: €7-15 per meal</li></ul><h3 id="best-cities-for-lgbtq-community" tabindex="-1">Best Cities for LGBTQ+ Community <a class="header-anchor" href="#best-cities-for-lgbtq-community" aria-label="Permalink to &quot;Best Cities for LGBTQ+ Community&quot;">​</a></h3><table tabindex="0"><thead><tr><th>City</th><th>LGBTQ+ Scene</th><th>Trans Healthcare</th></tr></thead><tbody><tr><td><strong>Warsaw</strong></td><td>Vibrant, active scene</td><td>Best options</td></tr><tr><td><strong>Kraków</strong></td><td>Active, growing scene</td><td>Good options</td></tr><tr><td><strong>Wrocław</strong></td><td>Moderate scene</td><td>Available</td></tr><tr><td><strong>Poznań</strong></td><td>Moderate scene</td><td>Available</td></tr><tr><td><strong>Gdańsk</strong></td><td>Moderate scene</td><td>Limited</td></tr></tbody></table><h4 id="cities-to-avoid" tabindex="-1">Cities to Avoid <a class="header-anchor" href="#cities-to-avoid" aria-label="Permalink to &quot;Cities to Avoid&quot;">​</a></h4><p>Many smaller cities and towns in the &quot;LGBTQ+ free zone&quot; regions (especially southeastern Poland) are actively hostile.</p><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Winters</strong>: Cold (-5°C to -10°C), snow common, limited daylight</li><li><strong>Summers</strong>: Mild to warm (15-25°C)</li><li><strong>Best time to arrive</strong>: Late spring/summer (May-September)</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li>Official language: Polish (West Slavic)</li><li>English: Moderate in cities, limited in rural areas</li><li>Polish is challenging to learn but essential for bureaucracy</li><li>Free Polish language courses available for immigrants</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.gov.pl/web/udsc" target="_blank" rel="noreferrer">Urząd do Spraw Cudzoziemców (Office for Foreigners)</a></li><li><a href="https://www.nfz.gov.pl/" target="_blank" rel="noreferrer">NFZ (National Health Fund)</a></li><li><a href="https://kph.org.pl/" target="_blank" rel="noreferrer">KPH (Campaign Against Homophobia)</a></li><li><a href="https://transfuzja.org/" target="_blank" rel="noreferrer">Trans-Fuzja Foundation</a></li><li><a href="https://www.otodom.pl/" target="_blank" rel="noreferrer">Otodom (housing)</a></li></ul>',29))])}const y=r(h,[["render",g]]);export{v as __pageData,y as default};
